@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.Localization.ILumeoLocalizer L
@inject IComponentInteropService Interop

<div class="@CssClass" @attributes="AdditionalAttributes">
    @* ── Toolbar ─────────────────────────────────────────────────────────── *@
    <div class="flex items-center gap-2 px-3 py-2 border-b border-border/40 bg-card shrink-0">
        @* Up button *@
        <Tooltip>
            <TooltipTrigger AsChild>
                <ChildContentSlot Context="slot">
                    <button type="button"
                            class="@UpButtonClass"
                            @onclick="NavigateUp"
                            disabled="@(_pathStack.Count == 0)"
                            aria-label="@L["FileManager.NavigateUp"]"
                            @attributes="slot.Attributes">
                        <Blazicon Svg="Lucide.ArrowUp" class="h-4 w-4" />
                    </button>
                </ChildContentSlot>
            </TooltipTrigger>
            <TooltipContent>@L["FileManager.UpOneLevel"]</TooltipContent>
        </Tooltip>

        @* Breadcrumb path *@
        <nav aria-label="@L["FileManager.Path"]" class="flex-1 min-w-0">
            <ol class="flex items-center flex-wrap gap-0.5 text-sm">
                @* Root segment *@
                <li>
                    <button type="button"
                            class="@BreadcrumbLinkClass"
                            @onclick="() => NavigateToStackDepth(-1)"
                            aria-label="@L["FileManager.Root"]">
                        <Blazicon Svg="Lucide.HardDrive" class="h-3.5 w-3.5" />
                    </button>
                </li>

                @for (int i = 0; i < _pathStack.Count; i++)
                {
                    var depth = i;
                    var seg = _pathStack[i];
                    var isLast = i == _pathStack.Count - 1;

                    <li class="flex items-center gap-0.5">
                        <span class="text-muted-foreground">/</span>
                        @if (isLast)
                        {
                            <span class="font-medium text-foreground truncate max-w-[120px]">@seg.Name</span>
                        }
                        else
                        {
                            <button type="button"
                                    class="@BreadcrumbLinkClass truncate max-w-[120px]"
                                    @onclick="() => NavigateToStackDepth(depth)">
                                @seg.Name
                            </button>
                        }
                    </li>
                }
            </ol>
        </nav>

        @* Toolbar actions *@
        <div class="flex items-center gap-1 shrink-0">
            @if (OnNewFolder.HasDelegate)
            {
                <Tooltip>
                    <TooltipTrigger AsChild>
                        <ChildContentSlot Context="slot">
                            <button type="button"
                                    class="@ToolbarButtonClass"
                                    @onclick="HandleNewFolder"
                                    aria-label="@L["FileManager.NewFolder"]"
                                    @attributes="slot.Attributes">
                                <Blazicon Svg="Lucide.FolderPlus" class="h-4 w-4" />
                            </button>
                        </ChildContentSlot>
                    </TooltipTrigger>
                    <TooltipContent>@L["FileManager.NewFolder"]</TooltipContent>
                </Tooltip>
            }
            @if (OnDelete.HasDelegate && _selectedNode is not null)
            {
                <Tooltip>
                    <TooltipTrigger AsChild>
                        <ChildContentSlot Context="slot">
                            <button type="button"
                                    class="@ToolbarButtonClass"
                                    @onclick="HandleDeleteSelected"
                                    aria-label="@L["FileManager.DeleteSelected"]"
                                    @attributes="slot.Attributes">
                                <Blazicon Svg="Lucide.Trash2" class="h-4 w-4" />
                            </button>
                        </ChildContentSlot>
                    </TooltipTrigger>
                    <TooltipContent>@L["FileManager.DeleteSelected"]</TooltipContent>
                </Tooltip>
            }
            <div class="w-px h-4 bg-border/60 mx-0.5"></div>
            @* View mode toggle *@
            <Tooltip>
                <TooltipTrigger AsChild>
                    <ChildContentSlot Context="slot">
                        <button type="button"
                                class="@(_viewMode == FileManagerViewMode.List ? ToolbarButtonActiveClass : ToolbarButtonClass)"
                                @onclick="() => SetViewMode(FileManagerViewMode.List)"
                                aria-label="@L["FileManager.SwitchListView"]"
                                aria-pressed="@(_viewMode == FileManagerViewMode.List)"
                                @attributes="slot.Attributes">
                            <Blazicon Svg="Lucide.List" class="h-4 w-4" />
                        </button>
                    </ChildContentSlot>
                </TooltipTrigger>
                <TooltipContent>@L["FileManager.ListView"]</TooltipContent>
            </Tooltip>
            <Tooltip>
                <TooltipTrigger AsChild>
                    <ChildContentSlot Context="slot">
                        <button type="button"
                                class="@(_viewMode == FileManagerViewMode.Grid ? ToolbarButtonActiveClass : ToolbarButtonClass)"
                                @onclick="() => SetViewMode(FileManagerViewMode.Grid)"
                                aria-label="@L["FileManager.SwitchGridView"]"
                                aria-pressed="@(_viewMode == FileManagerViewMode.Grid)"
                                @attributes="slot.Attributes">
                            <Blazicon Svg="Lucide.LayoutGrid" class="h-4 w-4" />
                        </button>
                    </ChildContentSlot>
                </TooltipTrigger>
                <TooltipContent>@L["FileManager.GridView"]</TooltipContent>
            </Tooltip>
        </div>
    </div>

    @* ── Body ─────────────────────────────────────────────────────────────── *@
    <div class="flex flex-1 min-h-0 overflow-hidden">

        @* ── Left: folder tree ──────────────────────────────────────────── *@
        <div class="w-52 shrink-0 border-e border-border/40 overflow-y-auto bg-card p-2" role="tree" aria-label="@L["FileManager.FolderTree"]">
            @foreach (var node in Root ?? [])
            {
                @RenderTreeNode(node, 0)
            }
        </div>

        @* ── Right: file list ───────────────────────────────────────────── *@
        <div id="@_fileListId" class="flex-1 overflow-auto bg-background p-2">
            @{
                var items = GetCurrentFolderContents();
                _fileItemCount = items.Count;
                // Keep the roving active index inside the rendered range so exactly
                // one row/tile stays in the tab sequence even after the folder's
                // contents shrink (otherwise no item would carry tabindex=0 and the
                // list would silently drop out of the tab order).
                if (_activeItemIndex >= _fileItemCount) _activeItemIndex = Math.Max(0, _fileItemCount - 1);
            }

            @if (_loadingFolder)
            {
                <div class="flex items-center justify-center h-32 text-muted-foreground text-sm">
                    <Blazicon Svg="Lucide.Loader" class="h-5 w-5 animate-spin me-2" />
                    @L["FileManager.Loading"]
                </div>
            }
            else if (items.Count == 0)
            {
                <div class="flex flex-col items-center justify-center h-32 text-center">
                    <Blazicon Svg="Lucide.FolderOpen" class="h-10 w-10 text-muted-foreground mb-3" />
                    <p class="text-sm font-medium text-foreground">@L["FileManager.EmptyTitle"]</p>
                    <p class="text-xs text-muted-foreground mt-1">@L["FileManager.EmptyState"]</p>
                </div>
            }
            else if (_viewMode == FileManagerViewMode.List)
            {
                @RenderListView(items)
            }
            else
            {
                @RenderGridView(items)
            }
        </div>
    </div>
</div>

@code {
    // ──────────────────────────────────────────────────────────────────────────
    // Parameters
    // ──────────────────────────────────────────────────────────────────────────

    [Parameter] public IReadOnlyList<FileSystemNode>? Root { get; set; }

    /// <summary>
    /// The ID of the currently open folder. Null means the root level.
    /// Uses <see cref="FileSystemNode.Id"/> as the path identifier.
    /// </summary>
    [Parameter] public string? CurrentPath { get; set; }
    [Parameter] public EventCallback<string?> CurrentPathChanged { get; set; }

    /// <summary>Called the first time a folder is opened if its Children is null. Return the loaded children.</summary>
    [Parameter] public Func<FileSystemNode, Task<List<FileSystemNode>>>? LoadChildren { get; set; }

    [Parameter] public FileManagerViewMode ViewMode { get; set; } = FileManagerViewMode.List;
    [Parameter] public EventCallback<FileManagerViewMode> ViewModeChanged { get; set; }

    [Parameter] public FileSystemNode? SelectedNode { get; set; }
    [Parameter] public EventCallback<FileSystemNode?> SelectedNodeChanged { get; set; }

    [Parameter] public EventCallback<FileSystemNode> OnFileOpen { get; set; }

    [Parameter] public EventCallback<(FileSystemNode Node, string NewName)> OnRename { get; set; }
    [Parameter] public EventCallback<IReadOnlyList<FileSystemNode>> OnDelete { get; set; }
    [Parameter] public EventCallback<FileSystemNode> OnNewFolder { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // ──────────────────────────────────────────────────────────────────────────
    // State
    // ──────────────────────────────────────────────────────────────────────────

    // Navigation stack: list of ancestor nodes from root to current folder
    private List<FileSystemNode> _pathStack = [];
    // The Root reference seen on the previous parameter set, used to detect a
    // tree swap so cached stack nodes from the old tree get discarded.
    private IReadOnlyList<FileSystemNode>? _lastRoot;
    private bool _loadingFolder;

    // ── Uncontrolled view-mode / selection backing state ──────────────────────
    // ViewMode and SelectedNode can be used uncontrolled (no *Changed delegate).
    // Storing the live value in the [Parameter] alone would let any unrelated
    // parent re-render re-push the parameter's default and wipe the user's
    // choice. So we keep a private backing field as the source of truth and only
    // adopt the parameter when it ACTUALLY changes (tracked by a separate param
    // snapshot, mirroring the _lastRoot pattern above).
    private FileManagerViewMode _viewMode = FileManagerViewMode.List;
    private FileManagerViewMode _lastViewModeParam = FileManagerViewMode.List;
    private bool _viewModeParamInit;
    private FileSystemNode? _selectedNode;
    private FileSystemNode? _lastSelectedParam;
    private bool _selectedParamInit;
    // Which nodes currently have their children expanded in the tree pane
    private readonly HashSet<string> _expandedTreeNodes = [];
    // Inline-rename state
    private FileSystemNode? _renamingNode;
    private string _renameValue = "";
    private readonly string _renameInputId = LumeoIds.New("fm-rename");
    // Set when a rename begins so OnAfterRender moves focus into the inline input
    // — otherwise keyboard users start a rename with no focused field.
    private bool _shouldFocusRenameInput;
    // Context menu state
    private FileSystemNode? _contextMenuNode;
    private bool _contextMenuOpen;
    private double _contextMenuX;
    private double _contextMenuY;
    private readonly string _contextMenuId = LumeoIds.New("fm-ctx");
    // Tracks whether the role=menu's focus trap is currently engaged so the
    // OnAfterRender hop only sets it up once per open and tears it down on close.
    // The trap (SetupFocusTrap) also SAVES the trigger element and RESTORES focus
    // to it on RemoveFocusTrap (#126: focus restore + Tab trapping), and lands
    // focus on the first menuitem so Arrow/Home/End nav works (#127).
    private bool _contextMenuTrapped;
    // Roving index across the open menu's menuitems, mirroring MenubarContent.
    private int _contextMenuFocusIndex = -1;

    // ── File list / grid roving-tabindex (a11y #128/#129) ─────────────────────
    // The file rows (list) and tiles (grid) form a single composite widget. Only
    // the active item carries tabindex=0 (the rest tabindex=-1) so the whole list
    // is a single tab stop; Arrow/Home/End move the active item and DOM focus.
    // A stable container id lets us register a native key-selective preventDefault
    // (Space/Enter/Arrows/Home/End would otherwise scroll the page — #129) and
    // focus the active item by id after an arrow move.
    private readonly string _fileListId = LumeoIds.New("fm-list");
    private int _activeItemIndex;
    private int _fileItemCount;
    // Whether the file-list scroll-suppression keys are registered with JS.
    private bool _fileListPdRegistered;
    private string FileItemId(int index) => $"{_fileListId}-item-{index}";

    // ──────────────────────────────────────────────────────────────────────────
    // CSS helpers
    // ──────────────────────────────────────────────────────────────────────────

    private string CssClass => Cx.Merge("flex flex-col rounded-lg border border-border/40 bg-card overflow-hidden h-full min-h-[400px]", Class);
    private const string ToolbarButtonClass = "inline-flex items-center justify-center h-7 w-7 rounded-md transition-colors hover:bg-accent text-muted-foreground hover:text-accent-foreground";
    private const string ToolbarButtonActiveClass = "inline-flex items-center justify-center h-7 w-7 rounded-md transition-colors bg-accent text-accent-foreground";
    private const string BreadcrumbLinkClass = "transition-colors hover:text-foreground text-muted-foreground rounded focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring";
    private const string UpButtonClass = "inline-flex items-center justify-center h-7 w-7 rounded-md transition-colors hover:bg-accent text-muted-foreground hover:text-accent-foreground disabled:opacity-40 disabled:pointer-events-none";

    // ──────────────────────────────────────────────────────────────────────────
    // Lifecycle
    // ──────────────────────────────────────────────────────────────────────────

    protected override async Task OnParametersSetAsync()
    {
        // Adopt ViewMode / SelectedNode from the parameter only when the consumer
        // actually changed the supplied value (or on first set), so an unrelated
        // parent re-render that re-pushes the same/default parameter does NOT
        // clobber an uncontrolled choice the user made via the toolbar / a click.
        if (!_viewModeParamInit || ViewMode != _lastViewModeParam)
        {
            _viewMode = ViewMode;
            _lastViewModeParam = ViewMode;
            _viewModeParamInit = true;
        }
        if (!_selectedParamInit || !ReferenceEquals(SelectedNode, _lastSelectedParam))
        {
            _selectedNode = SelectedNode;
            _lastSelectedParam = SelectedNode;
            _selectedParamInit = true;
        }

        // Detect a Root replacement. If the consumer swaps in a fresh tree, any
        // nodes cached in _pathStack point at the OLD tree and must be discarded
        // — otherwise GetCurrentFolderContents returns the previous tree's
        // children. Comparing by reference catches the swap even when
        // CurrentPath is unchanged (which the Id-equality early-return below
        // would otherwise treat as a no-op, keeping the stale node).
        var rootChanged = !ReferenceEquals(Root, _lastRoot);
        _lastRoot = Root;
        if (rootChanged)
        {
            _pathStack = [];

            // The selected node may have been deleted (or filtered) out of the
            // refreshed tree. Drop a now-orphaned selection so the Delete toolbar
            // button doesn't stay active against a node that no longer exists.
            // Only reconcile against a genuinely-present tree (Root non-null) and
            // skip when the consumer just re-supplied this exact selection this
            // render (it is authoritative then).
            if (_selectedNode is not null
                && !ReferenceEquals(_selectedNode, _lastSelectedParam)
                && Root is not null
                && !ContainsNodeId(Root, _selectedNode.Id))
            {
                _selectedNode = null;
                await SelectedNodeChanged.InvokeAsync(null);
            }
        }

        // Sync _pathStack when CurrentPath is changed externally
        if (CurrentPath is null)
        {
            _pathStack = [];
            return;
        }

        // If path stack already ends at this id, nothing to do — UNLESS the live
        // tree has replaced that node in place. A consumer can refresh a folder
        // by swapping in a fresh FileSystemNode (new Children) at the same Id
        // while keeping the SAME Root list reference; then rootChanged above is
        // false and an Id-equality early-return would latch the stale cached node
        // (GetCurrentFolderContents returns its old Children). Re-resolve the
        // current node from the live Root by Id and only short-circuit when it is
        // the very same instance we already hold; otherwise fall through to
        // rebuild the stack from the fresh tree.
        if (_pathStack.Count > 0 && _pathStack[^1].Id == CurrentPath)
        {
            var liveStack = new List<FileSystemNode>();
            if (FindPath(Root ?? [], CurrentPath, liveStack)
                && ReferenceEquals(liveStack[^1], _pathStack[^1]))
                return;
        }

        // Rebuild stack by finding the path in the tree
        var newStack = new List<FileSystemNode>();
        if (FindPath(Root ?? [], CurrentPath, newStack))
            _pathStack = newStack;

        // Ensure current folder's children are loaded
        if (_pathStack.Count > 0)
        {
            var current = _pathStack[^1];
            if (current.IsFolder && current.Children is null && LoadChildren is not null)
            {
                _loadingFolder = true;
                try
                {
                    current.Children = await LoadChildren(current);
                }
                finally
                {
                    _loadingFolder = false;
                }
            }
        }
    }

    // ──────────────────────────────────────────────────────────────────────────
    // Navigation helpers
    // ──────────────────────────────────────────────────────────────────────────

    private List<FileSystemNode> GetCurrentFolderContents()
    {
        if (_pathStack.Count == 0)
            return (Root ?? []).ToList();

        var current = _pathStack[^1];
        return current.Children ?? [];
    }

    // Depth-first check for a node with the given Id anywhere in the tree. Used
    // to reconcile an orphaned selection after a Root refresh (deleted/filtered).
    private static bool ContainsNodeId(IEnumerable<FileSystemNode> nodes, string targetId)
    {
        foreach (var node in nodes)
        {
            if (node.Id == targetId)
                return true;
            if (node.Children is { Count: > 0 } && ContainsNodeId(node.Children, targetId))
                return true;
        }
        return false;
    }

    private static bool FindPath(IEnumerable<FileSystemNode> nodes, string targetId, List<FileSystemNode> stack)
    {
        foreach (var node in nodes)
        {
            if (node.Id == targetId)
            {
                stack.Add(node);
                return true;
            }
            if (node.IsFolder && node.Children is { Count: > 0 })
            {
                stack.Add(node);
                if (FindPath(node.Children, targetId, stack))
                    return true;
                stack.RemoveAt(stack.Count - 1);
            }
        }
        return false;
    }

    private async Task NavigateToFolder(FileSystemNode folder)
    {
        // Build new path stack up to this folder
        var newStack = new List<FileSystemNode>();
        if (!FindPath(Root ?? [], folder.Id, newStack))
            return;

        _pathStack = newStack;

        // Lazy-load children if needed
        if (folder.Children is null && LoadChildren is not null)
        {
            _loadingFolder = true;
            StateHasChanged();
            try
            {
                folder.Children = await LoadChildren(folder);
            }
            finally
            {
                _loadingFolder = false;
            }
        }

        // Expand in tree pane
        _expandedTreeNodes.Add(folder.Id);

        CurrentPath = folder.Id;
        await CurrentPathChanged.InvokeAsync(CurrentPath);
    }

    private async Task NavigateToStackDepth(int depth)
    {
        if (depth < 0)
        {
            // Navigate to root
            _pathStack = [];
            CurrentPath = null;
            await CurrentPathChanged.InvokeAsync(null);
            return;
        }

        _pathStack = _pathStack.Take(depth + 1).ToList();
        CurrentPath = _pathStack[^1].Id;
        await CurrentPathChanged.InvokeAsync(CurrentPath);
    }

    private async Task NavigateUp()
    {
        if (_pathStack.Count == 0) return;
        await NavigateToStackDepth(_pathStack.Count - 2);
    }

    // ──────────────────────────────────────────────────────────────────────────
    // View mode
    // ──────────────────────────────────────────────────────────────────────────

    private async Task SetViewMode(FileManagerViewMode mode)
    {
        // Drive the private backing field (the render source of truth) — NOT the
        // [Parameter] — so an uncontrolled choice survives unrelated parent
        // re-renders that re-push the default. Do NOT touch _lastViewModeParam:
        // it must keep tracking what the PARENT last supplied, so a later
        // same-default re-push is still recognised as "no external change". A
        // controlled consumer reconciles via OnParametersSetAsync when its bound
        // value comes back through ViewModeChanged below.
        _viewMode = mode;
        await ViewModeChanged.InvokeAsync(mode);
    }

    // ──────────────────────────────────────────────────────────────────────────
    // Selection
    // ──────────────────────────────────────────────────────────────────────────

    // Click handler for a row/tile: sync the roving active index to the clicked
    // item (so a subsequent Arrow keypress continues from where the user clicked)
    // then run the normal selection.
    private async Task SelectRow(FileSystemNode node, int index)
    {
        _activeItemIndex = index;
        await SelectNode(node);
    }

    private async Task SelectNode(FileSystemNode node)
    {
        // Drive the private backing field — NOT the [Parameter] — so an
        // uncontrolled selection survives unrelated parent re-renders that
        // re-push the default (null). _lastSelectedParam keeps tracking the
        // PARENT's last-supplied value so a later same-value re-push isn't
        // mistaken for a genuine external change. A controlled consumer
        // reconciles via OnParametersSetAsync when its bound value flows back
        // through SelectedNodeChanged below.
        _selectedNode = node;
        await SelectedNodeChanged.InvokeAsync(node);
    }

    private async Task HandleNodeDoubleClick(FileSystemNode node)
    {
        if (node.IsFolder)
        {
            await NavigateToFolder(node);
        }
        else
        {
            await SelectNode(node);
            await OnFileOpen.InvokeAsync(node);
        }
    }

    // Keyboard handler for file rows / grid tiles (a11y): Enter opens (folder
    // navigate / file open), Space selects, Arrow/Home/End roves the active item.
    // Mirrors the click/double-click mouse affordances AND adds roving-tabindex
    // arrow navigation so the role=grid / role=listbox containers behave as a
    // single composite widget per the WAI-ARIA pattern (#128). The actual
    // page-scroll suppression for Space/Arrows is wired natively via
    // RegisterPreventDefaultKeys in OnAfterRenderAsync (#129) — not
    // @onkeydown:preventDefault, which would also swallow Tab.
    private async Task HandleRowKeyDown(FileSystemNode node, int index, KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Enter":
                await HandleNodeDoubleClick(node);
                return;
            case " ":
            case "Spacebar": // legacy key name
                await SelectNode(node);
                return;
            case "ArrowDown":
            case "ArrowRight":
                await MoveActiveItem(index + 1);
                return;
            case "ArrowUp":
            case "ArrowLeft":
                await MoveActiveItem(index - 1);
                return;
            case "Home":
                await MoveActiveItem(0);
                return;
            case "End":
                await MoveActiveItem(_fileItemCount - 1);
                return;
        }
    }

    // Roving tabindex: clamp to the rendered range, flip the active item (which
    // re-renders the new item with tabindex=0 and the old one with -1), then move
    // DOM focus to it by id. Out-of-range targets are ignored so the active item
    // never leaves the list.
    private async Task MoveActiveItem(int target)
    {
        if (_fileItemCount == 0) return;
        var next = Math.Clamp(target, 0, _fileItemCount - 1);
        if (next == _activeItemIndex) return;
        _activeItemIndex = next;
        StateHasChanged();
        try { await Interop.FocusElement(FileItemId(next)); } catch (JSDisconnectedException) { }
    }

    // ──────────────────────────────────────────────────────────────────────────
    // Context menu / toolbar operations
    // ──────────────────────────────────────────────────────────────────────────

    private void OpenContextMenu(FileSystemNode node, MouseEventArgs e)
    {
        _contextMenuNode = node;
        _contextMenuX = e.ClientX;
        _contextMenuY = e.ClientY;
        _contextMenuOpen = true;
        _contextMenuFocusIndex = -1;
    }

    private async Task CloseContextMenu()
    {
        if (!_contextMenuOpen) return;
        _contextMenuOpen = false;
        _contextMenuNode = null;
        // Release the Tab-cycling trap; RemoveFocusTrap also returns focus to the
        // element that was focused when the menu opened — the row or actions
        // button — so keyboard focus is never stranded after close (#126: WCAG
        // 2.4.3). Also drop the arrow-scroll suppression.
        if (_contextMenuTrapped)
        {
            _contextMenuTrapped = false;
            _contextMenuFocusIndex = -1;
            try { await Interop.RemoveFocusTrap(_contextMenuId); } catch (JSDisconnectedException) { }
            try { await Interop.UnregisterPreventDefaultKeys(_contextMenuId); } catch (JSDisconnectedException) { }
        }
    }

    private async Task HandleContextMenuKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await CloseContextMenu();
                return;
            case "ArrowDown":
            {
                var count = await Interop.GetMenuItemCount(_contextMenuId);
                if (count > 0)
                {
                    _contextMenuFocusIndex = (_contextMenuFocusIndex + 1) % count;
                    await Interop.FocusMenuItemByIndex(_contextMenuId, _contextMenuFocusIndex);
                }
                return;
            }
            case "ArrowUp":
            {
                var count = await Interop.GetMenuItemCount(_contextMenuId);
                if (count > 0)
                {
                    _contextMenuFocusIndex = _contextMenuFocusIndex <= 0 ? count - 1 : _contextMenuFocusIndex - 1;
                    await Interop.FocusMenuItemByIndex(_contextMenuId, _contextMenuFocusIndex);
                }
                return;
            }
            case "Home":
            {
                var count = await Interop.GetMenuItemCount(_contextMenuId);
                if (count > 0)
                {
                    _contextMenuFocusIndex = 0;
                    await Interop.FocusMenuItemByIndex(_contextMenuId, _contextMenuFocusIndex);
                }
                return;
            }
            case "End":
            {
                var count = await Interop.GetMenuItemCount(_contextMenuId);
                if (count > 0)
                {
                    _contextMenuFocusIndex = count - 1;
                    await Interop.FocusMenuItemByIndex(_contextMenuId, _contextMenuFocusIndex);
                }
                return;
            }
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Engage a Tab-cycling focus trap on the open menu. SetupFocusTrap saves
        // the element that had focus (the row / actions button) so RemoveFocusTrap
        // can restore it on close, traps Tab/Shift+Tab inside the menu (#126), and
        // lands focus on the first menuitem so Arrow/Home/End nav is reachable
        // (#127). The Arrow/Home/End keys also scroll the page by default — suppress
        // them in JS (Escape has no scroll default) so keyboard menu navigation
        // doesn't scroll behind the open menu.
        if (_contextMenuOpen && !_contextMenuTrapped)
        {
            _contextMenuTrapped = true;
            try
            {
                await Interop.RegisterPreventDefaultKeys(_contextMenuId, new[]
                {
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowDown"),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowUp"),
                    new Lumeo.Services.PreventDefaultKeyRule("Home"),
                    new Lumeo.Services.PreventDefaultKeyRule("End"),
                });
            }
            catch (JSDisconnectedException) { }
            try { await Interop.SetupFocusTrap(_contextMenuId); } catch (JSDisconnectedException) { }
        }

        // Auto-focus the inline rename field the render after a rename begins so
        // keyboard users can type immediately (mirrors the context-menu path).
        if (_shouldFocusRenameInput && _renamingNode is not null)
        {
            _shouldFocusRenameInput = false;
            try { await Interop.FocusElement(_renameInputId); } catch (JSDisconnectedException) { }
        }

        // Register the native scroll-suppression for the file list once it exists
        // (#129: Space / Arrows would otherwise scroll the page). SkipEditable
        // keeps typing in the inline rename input alive. Registered here rather
        // than via @onkeydown:preventDefault so Tab is never swallowed.
        if (!_fileListPdRegistered)
        {
            _fileListPdRegistered = true;
            try
            {
                await Interop.RegisterPreventDefaultKeys(_fileListId, new[]
                {
                    new Lumeo.Services.PreventDefaultKeyRule(" ", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("Spacebar", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowDown", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowUp", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowLeft", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowRight", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("Home", SkipEditable: true),
                    new Lumeo.Services.PreventDefaultKeyRule("End", SkipEditable: true),
                });
            }
            catch (JSDisconnectedException) { }
            catch (InvalidOperationException) { } // JS interop unavailable during prerender
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_contextMenuTrapped)
        {
            try { await Interop.RemoveFocusTrap(_contextMenuId); } catch (JSDisconnectedException) { }
            try { await Interop.UnregisterPreventDefaultKeys(_contextMenuId); } catch (JSDisconnectedException) { }
        }
        if (_fileListPdRegistered)
        {
            try { await Interop.UnregisterPreventDefaultKeys(_fileListId); } catch (JSDisconnectedException) { }
        }
    }

    private async Task BeginRename(FileSystemNode node)
    {
        await CloseContextMenu();
        _renamingNode = node;
        _renameValue = node.Name;
        // Move focus into the inline input on the next render so keyboard users
        // can edit immediately (mirrors the context-menu focus path).
        _shouldFocusRenameInput = true;
    }

    private async Task CommitRename()
    {
        if (_renamingNode is null) return;
        var node = _renamingNode;
        var newName = _renameValue.Trim();
        _renamingNode = null;
        _renameValue = "";

        if (!string.IsNullOrWhiteSpace(newName) && newName != node.Name)
            await OnRename.InvokeAsync((node, newName));
    }

    private void CancelRename()
    {
        _renamingNode = null;
        _renameValue = "";
    }

    private async Task HandleDeleteNode(FileSystemNode node)
    {
        await CloseContextMenu();
        await ClearSelectionIfDeleted(node);
        await OnDelete.InvokeAsync([node]);
    }

    private async Task HandleDeleteSelected()
    {
        if (_selectedNode is null) return;
        var node = _selectedNode;
        await ClearSelectionIfDeleted(node);
        await OnDelete.InvokeAsync([node]);
    }

    // Drop the live selection when the node being deleted is the selected one, so
    // the Delete toolbar button (gated on _selectedNode is not null) doesn't stay
    // active against an already-removed node. Fired before OnDelete so the
    // selection clears regardless of how the consumer mutates the tree.
    private async Task ClearSelectionIfDeleted(FileSystemNode deleted)
    {
        if (_selectedNode is null || _selectedNode.Id != deleted.Id) return;
        _selectedNode = null;
        await SelectedNodeChanged.InvokeAsync(null);
    }

    private async Task HandleNewFolder()
    {
        var currentFolder = _pathStack.Count > 0 ? _pathStack[^1] : null;
        await OnNewFolder.InvokeAsync(currentFolder ?? new FileSystemNode { Id = "", Name = "Root", IsFolder = true });
    }

    private async Task HandleOpenNode(FileSystemNode node)
    {
        await CloseContextMenu();
        if (node.IsFolder)
            await NavigateToFolder(node);
        else
            await OnFileOpen.InvokeAsync(node);
    }

