    // ──────────────────────────────────────────────────────────────────────────
    // Icon resolution
    // ──────────────────────────────────────────────────────────────────────────

    private static SvgIcon GetNodeIcon(FileSystemNode node)
    {
        if (!string.IsNullOrEmpty(node.IconName))
        {
            // Try to look up by name via reflection — fall through to defaults if missing
            var prop = typeof(Lucide).GetProperty(node.IconName,
                System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Static);
            if (prop?.GetValue(null) is SvgIcon icon) return icon;
        }

        if (node.IsFolder) return Lucide.Folder;

        var ext = System.IO.Path.GetExtension(node.Name).ToLowerInvariant();
        return ext switch
        {
            ".png" or ".jpg" or ".jpeg" or ".gif" or ".svg" or ".webp" or ".bmp" or ".ico" => Lucide.Image,
            ".pdf" => Lucide.FileText,
            ".zip" or ".tar" or ".gz" or ".rar" or ".7z" or ".bz2" => Lucide.FileArchive,
            ".mp3" or ".wav" or ".ogg" or ".flac" or ".aac" or ".m4a" => Lucide.Music,
            ".mp4" or ".mov" or ".avi" or ".mkv" or ".webm" or ".wmv" => Lucide.Video,
            ".txt" or ".md" or ".log" or ".rst" or ".rtf" => Lucide.FileText,
            ".cs" or ".js" or ".ts" or ".jsx" or ".tsx" or ".razor" or ".json" or ".xml"
                or ".html" or ".htm" or ".css" or ".scss" or ".less" or ".yaml" or ".yml"
                or ".toml" or ".ini" or ".sh" or ".bash" or ".ps1" or ".py" or ".rb"
                or ".java" or ".cpp" or ".c" or ".h" or ".go" or ".rs" or ".swift" => Lucide.FileCode,
            _ => Lucide.File
        };
    }

    // ──────────────────────────────────────────────────────────────────────────
    // Size formatting
    // ──────────────────────────────────────────────────────────────────────────

    private static string FormatSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        if (bytes < 1024L * 1024 * 1024) return $"{bytes / (1024.0 * 1024):F1} MB";
        return $"{bytes / (1024.0 * 1024 * 1024):F1} GB";
    }

